args.sparql:
SELECT ?player ?playerLabel (COUNT(?event) AS ?count)
WHERE {
  ?event wdt:P31 wd:Q248297;
        wdt:P361 wd:Q41520.
  ?player wdt:P21 wd:Q6581072;
        p:P710 [ ps:P710 ?event; pq:P2132 wd:Q2670332 ].
  OPTIONAL { ?player rdfs:label ?playerLabel. FILTER(LANG(?playerLabel) = "en") }
}
GROUP BY ?player ?playerLabel
HAVING (COUNT(?event) >= 3 && COUNT(?event) <= 7)
